.step-indicator ol {
    counter-reset: step;
    position: relative;
}

.step-item {
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.completed + .step-item.active::before {
    background-color: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    position: relative;
    z-index: 1;
    background-color: #e9ecef;
    color: #6c757d;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
}

.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #adb5bd;
}

.step-label {
    display: block;
    font-size: 0.8rem;
    margin-top: 0.35rem;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-label {
    color: #adb5bd;
}

.step-btn {
    background: none;
    border: none;
    cursor: default;
}

.step-item.completed .step-btn {
    cursor: pointer;
}

@using sv_4cd09baafbb0471393042e3fc4ab7e9f.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(Touched && string.IsNullOrWhiteSpace(FullName) ? "is-invalid" : "")"
               value="@FullName"
               @oninput="e => FullName = (string?)e.Value ?? string.Empty" />
        <div class="invalid-feedback">Full name is required.</div>
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(Touched && string.IsNullOrWhiteSpace(Email) ? "is-invalid" : "")"
               value="@Email"
               @oninput="e => Email = (string?)e.Value ?? string.Empty" />
        <div class="invalid-feedback">Email is required.</div>
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control @(Touched && string.IsNullOrWhiteSpace(Phone) ? "is-invalid" : "")"
               value="@Phone"
               @oninput="e => Phone = (string?)e.Value ?? string.Empty" />
        <div class="invalid-feedback">Phone number is required.</div>
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(Touched && string.IsNullOrWhiteSpace(Address) ? "is-invalid" : "")"
               value="@Address"
               @oninput="e => Address = (string?)e.Value ?? string.Empty" />
        <div class="invalid-feedback">Address is required.</div>
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Validating…</text>
        }
        else
        {
            <text>Next</text>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string FullName = "";
    private string Email = "";
    private string Phone = "";
    private string Address = "";
    private bool Touched;
    private bool IsValidating;
    private string? ErrorMessage;

    protected override void OnParametersSet()
    {
        FullName = Model.FullName;
        Email = Model.Email;
        Phone = Model.Phone;
        Address = Model.Address;
    }

    private async Task HandleNext()
    {
        Touched = true;
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Please fill in all required fields.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email.Trim());
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid. Please correct it.";
                return;
            }

            var info = new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim());
            await OnNext.InvokeAsync(info);
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@using sv_4cd09baafbb0471393042e3fc4ab7e9f.Models

<h4 class="mb-3">Work History</h4>

@for (var i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="@Entries[index]"
                     Index="index"
                     CanRemove="@(Entries.Count > 1)"
                     OnChanged="entry => UpdateEntry(index, entry)"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void UpdateEntry(int index, WorkEntry entry)
    {
        Entries[index] = entry;
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var e in Entries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate == default)
            {
                ErrorMessage = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
