    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string FullName = "";
    private string Email = "";
    private string Phone = "";
    private string Address = "";
    private bool Touched;
    private bool IsValidating;
    private string? ErrorMessage;

    protected override void OnParametersSet()
    {
        FullName = Model.FullName;
        Email = Model.Email;
        Phone = Model.Phone;
        Address = Model.Address;
    }

    private async Task HandleNext()
    {
        Touched = true;
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Please fill in all required fields.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email.Trim());
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid. Please correct it.";
                return;
            }

            var info = new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim());
            await OnNext.InvokeAsync(info);
        }
        finally
        {
            IsValidating = false;
        }
    }
}

