{"file_text": "@using sv_4cd09baafbb0471393042e3fc4ab7e9f.Models

<h4 class="mb-3">Work History</h4>

@for (var i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="@Entries[index]"
                     Index="index"
                     CanRemove="@(Entries.Count > 1)"
                     OnChanged="entry => UpdateEntry(index, entry)"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void UpdateEntry(int index, WorkEntry entry)
    {
        Entries[index] = entry;
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var e in Entries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate == default)
            {
                ErrorMessage = "Each position requires a company name, job title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}
