{"file_text": "@using sv_4cd09baafbb0471393042e3fc4ab7e9f.Models

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">🎉 Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>@ApplicationId</strong>. Please save this for your records.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.EndDate.HasValue ? entry.EndDate.Value.ToString("MMM yyyy") : "Present")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small class="text-muted">@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <text>Submitting…</text>
            }
            else
            {
                <text>Submit Application</text>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal,
                new WorkHistory(WorkEntries),
                References,
                CoverLetter);

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
