.step-indicator ol {
    counter-reset: step;
    position: relative;
}

.step-item {
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.completed + .step-item.active::before {
    background-color: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    position: relative;
    z-index: 1;
    background-color: #e9ecef;
    color: #6c757d;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
}

.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #adb5bd;
}

.step-label {
    display: block;
    font-size: 0.8rem;
    margin-top: 0.35rem;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-label {
    color: #adb5bd;
}

.step-btn {
    background: none;
    border: none;
    cursor: default;
}

.step-item.completed .step-btn {
    cursor: pointer;
}

