toolArgs.file_text:
@using sv_4cd09baafbb0471393042e3fc4ab7e9f.Models

<h4 class="mb-3">References</h4>

@for (var i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Reference="@References[index]"
                     Index="index"
                     CanRemove="@(References.Count > 2)"
                     OnChanged="r => UpdateReference(index, r)"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new Reference("", "", "", ""));
    }

    private void UpdateReference(int index, Reference r)
    {
        References[index] = r;
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "Please provide at least 2 references.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync(References);
    }
