@page "/apply"
@using sv_4cd09baafbb0471393042e3fc4ab7e9f.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep"
                   CompletedSteps="@completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="@personalInfo"
                              ApplicationService="@ApplicationService"
                              OnNext="HandlePersonalInfoNext" />
            break;
        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             OnNext="HandleWorkHistoryNext"
                             OnBack="GoBack" />
            break;
        case 2:
            <ReferencesStep References="@references"
                            OnNext="HandleReferencesNext"
                            OnBack="GoBack" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="GoBack" />
            break;
        case 4:
            <ReviewStep Personal="@personalInfo"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        ApplicationService="@ApplicationService"
                        OnEditSection="GoToStep"
                        OnBack="GoBack" />
            break;
    }
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = [];

    private PersonalInfo personalInfo = new("", "", "", "");
    private List<WorkEntry> workEntries = [new("", "", DateTime.Today, null, "")];
    private List<Reference> references = [new("", "", "", ""), new("", "", "", "")];
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private void GoBack()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void AdvanceStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void HandlePersonalInfoNext(PersonalInfo info)
    {
        personalInfo = info;
        AdvanceStep();
    }

    private void HandleWorkHistoryNext(List<WorkEntry> entries)
    {
        workEntries = entries;
        AdvanceStep();
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        AdvanceStep();
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        AdvanceStep();
    }
}

